package sort;

import java.util.ArrayList;
import java.util.Arrays;
import java.util.Collections;
import java.util.Comparator;
import java.util.Iterator;

public class TestArrayListSort {

	public static void main(String[] args) {
		
		ArrayList<Integer> list = new ArrayList<>(); // <> 안에는 int 를 쓰면 error 가 난다 무조건 class 타입을 써야함 (예. double > Double)
		list.add(10);
		list.add(5);
		list.add(34);
		list.add(28);
		list.add(16);
		
		
		// 익명클래스 사용하여 코딩을 부여하면 Interface 도 new 가능하다
		Comparator<Integer> compAsc = new Comparator<Integer>() { // interface 라서 코딩이 있다면 new 를 쓸 수 있음
			
			@Override
			public int compare(Integer o1, Integer o2) {
				
				
				return o1 - o2;
			}
		};
		Comparator<Integer> compDesc = new Comparator<Integer>() { // interface 라서 코딩이 있다면 new 를 쓸 수 있음
			
			@Override
			public int compare(Integer o1, Integer o2) {
				
				
				return o2 - o1;
			}
		};
		
		disp_list(list); // 10,5,34,28,16,
		// 오름차순 정렬
		Collections.sort(list, compAsc);
		disp_list(list); // 5,10,16,28,34,
		// 내림차순 정렬
		Collections.sort(list, compDesc);
		disp_list(list); // 34,28,16,10,5,
		line();
		// 문자열 배열
		ArrayList<String> names = new ArrayList<>();
		names.add("이순신");
		names.add("김유신");
		names.add("강감찬");
		names.add("을지문덕");
		names.add("권율");
		
		disp_name(names);
		// Ascending Sort
		Collections.sort(names, new Comparator<String>() {

			@Override
			public int compare(String o1, String o2) {
				return o1.compareTo(o2);
			}
		});
		disp_name(names);
		
		// Descending Sort
		Collections.sort(names, new Comparator<String>() {

		@Override
		public int compare(String o1, String o2) {
			return o2.compareTo(o1);
		}
		});
		disp_name(names);

	}

	private static void disp_name(ArrayList<String> names) {
		
		for (String name : names) {
			System.out.print( name + "," );
			
		}
		System.out.println();
		
	}

	private static void line() {
		
		System.out.println("");
		
		
	}

	private static void disp_list(ArrayList<Integer> list) {
		
		for (Integer num : list) {
			System.out.print(num + ",");
		}
		System.out.println();
		
	}

}
